"use client";
import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Send, Play } from 'lucide-react';

const mockContext = {
  weather: 'nice and sunny', 
  userMood: 'happy', 
  pastOrders: ['Iced Caramel Macchiato']
};

const TypewriterMessage = ({ text, onComplete, fastForward, onUpdate }) => {
  const [displayed, setDisplayed] = useState('');
  const isFinished = useRef(false);
  
  useEffect(() => {
    if (isFinished.current) return;

    if (fastForward) {
       setDisplayed(text);
       isFinished.current = true;
       if (onComplete) onComplete();
       if (onUpdate) onUpdate();
       return;
    }

    let index = 0;
    let currentText = ''; 
    setDisplayed(''); 
    
    // Safely decompose Unicode arrays to ensure emojis do not split!
    const characters = Array.from(text);
    
    const timer = setInterval(() => {
      if (index < characters.length) {
        currentText += characters[index];
        setDisplayed(currentText);
        index++;
        if (onUpdate) onUpdate();
      } else {
        clearInterval(timer);
        isFinished.current = true;
        if (onComplete) onComplete();
      }
    }, 15);
    
    return () => clearInterval(timer);
  }, [text, onComplete, fastForward, onUpdate]);

  return <span>{displayed}</span>;
};

const Kiosk = () => {
  const [inputText, setInputText] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [fastForward, setFastForward] = useState(false);

  const [messages, setMessages] = useState([
    {
      id: 1,
      sender: 'Meowow',
      text: "Hello and welcome to CafeMo! Looking for something?",
      typewriter: true,
      options: ['Recommend me a drink!', 'Show me all the menu!']
    }
  ]);
  const [orderStage, setOrderStage] = useState('GATHERING'); 
  const messagesEndRef = useRef(null);

  useEffect(() => {
    setIsTyping(true);
  }, []);

  useEffect(() => {
    if (!isTyping) {
       messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages, isTyping]);

  const handleTypingComplete = useCallback(() => {
    setIsTyping(false);
  }, []);

  const handleTypingUpdate = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'auto' });
  }, []);

  const handleSend = async (overrideText) => {
    const textToProcess = typeof overrideText === 'string' ? overrideText : inputText;
    
    if (isTyping && !overrideText) {
       setFastForward(true);
       return;
    }
    
    if (!textToProcess.trim()) return;

    if (textToProcess === inputText) setInputText('');

    // Remove options from all previous messages
    setMessages(prev => prev.map(msg => ({ ...msg, options: [] })));

    const userMsg = { id: Date.now(), sender: 'user', text: textToProcess };
    setMessages(prev => [...prev, userMsg]);
    
    setMessages(prev => [...prev, { id: 'temp-thought', sender: 'Meowow', text: "...", typewriter: false }]);

    try {
      const chatHistory = messages
          .filter(m => m.sender !== 'System' && m.id !== 'temp-thought')
          .map(m => ({
             role: m.sender === 'user' ? 'user' : 'assistant',
             content: m.text
          }));

      const activePrompt = `Current Context - Weather: ${mockContext.weather}, User Mood: ${mockContext.userMood}. User past favorite orders: ${mockContext.pastOrders.join(', ')}. User Message: "${textToProcess}"`;

      const systemPrompt = `You are Meowow, an intelligent, friendly barista mascot at CafeMo acting as an interactive AI kiosk. Keep responses strictly under 2 sentences. Be cheerful. 
CRITICAL: You MUST provide EXACTLY 1-3 short interactive choices for the user to respond with at the very end of your response formatted like this: [OPTIONS: Opt 1 | Opt 2 | Opt 3]. Make the first option the primary/confirmation choice.
CRITICAL: If you are actively recommending a specific drink, you MUST output [IMAGE: drink_name] exactly once in your response. 
CRITICAL: When the customer has confirmed their customized order and is fully ready to place it, you MUST append the exact string '[FINALIZED]' at the very end. Never use markdown.`;

      const res = await fetch("https://api.groq.com/openai/v1/chat/completions", {
          method: "POST",
          headers: {
             "Authorization": "Bearer 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",
             "Content-Type": "application/json"
          },
          body: JSON.stringify({
             model: "llama-3.1-8b-instant",
             messages: [
                { role: "system", content: systemPrompt },
                ...chatHistory,
                { role: "user", content: activePrompt }
             ],
             temperature: 0.7,
             max_tokens: 150
          })
      });

      const data = await res.json();
      let aiResponse = data.choices[0].message.content.trim().replace(/\*/g, '');

      let isFinalized = false;
      if (aiResponse.includes('[FINALIZED]')) {
          isFinalized = true;
          aiResponse = aiResponse.replace(/\[FINALIZED\]/g, '').trim();
      }
      
      let imageUrl = null;
      const imageMatch = aiResponse.match(/\[IMAGE:\s*(.*?)\]/i);
      if (imageMatch) {
          imageUrl = '/frappe.png'; // Using our generated placeholder strictly
          aiResponse = aiResponse.replace(/\[IMAGE:.*?\]/ig, '').trim();
      }

      let parsedOptions = [];
      const optionsMatch = aiResponse.match(/\[OPTIONS:\s*(.*?)\]/i);
      if (optionsMatch) {
          parsedOptions = optionsMatch[1].split('|').map(s => s.trim());
          aiResponse = aiResponse.replace(/\[OPTIONS:.*?\]/ig, '').trim();
      } else {
          // Fallback if LLM forgets
          parsedOptions = isFinalized ? [] : ["I'll take it!", "Actually no"];
      }

      setMessages(prev => prev.filter(m => m.id !== 'temp-thought'));
      
      setFastForward(false);
      setIsTyping(true); 
      setMessages(prev => [...prev, {
          id: Date.now() + 1,
          sender: 'Meowow',
          text: aiResponse,
          image: imageUrl,
          options: isFinalized ? [] : parsedOptions,
          typewriter: true 
      }]);

      if (isFinalized) {
         setOrderStage('PROCESSING');
         const timeToWait = aiResponse.length * 15 + 1000;
         setTimeout(() => {
             setMessages(prev => [...prev, {
                id: Date.now() + 2,
                sender: 'System',
                isSystem: true,
                text: "⚙️ Order Sent to Kitchen!"
             }]);
             setOrderStage('COMPLETED');
         }, timeToWait);
      }

    } catch (e) {
      console.error("Groq API Error:", e);
      setMessages(prev => prev.filter(m => m.id !== 'temp-thought'));
      
      setFastForward(false);
      setIsTyping(true);
      setMessages(prev => [...prev, {
          id: Date.now() + 1,
          sender: 'Meowow',
          text: "Oops! My brain got disconnected from the server. Can you repeat that?",
          typewriter: true,
          options: ["Try again!"]
      }]);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') handleSend();
  };

  const handleBubbleClick = () => {
    if (isTyping) {
       setFastForward(true);
    }
  };

  return (
    <div className="flex w-full h-[100dvh] bg-[#f7ead6] items-center justify-center overflow-hidden relative font-sans">
      
      <div className="relative w-full max-w-[1300px] h-full flex flex-row items-end z-10 px-8 lg:px-16 pb-12 pt-12">
        
        {/* Mascot Left Panel */}
        <div className="w-[35%] h-full flex items-end justify-end pointer-events-none z-20 pb-0 shrink-0 -mr-16 -mb-8">
          <img 
            src={isTyping ? "/placeholder.gif" : "/placeholder.png"} 
            alt="Mascot Avatar" 
            className="w-[220%] max-w-[1200px] min-w-[550px] translate-x-24 translate-y-[20%] object-contain transition-all"
          />
        </div>

        {/* Right Chat Container styled like a massive speech bubble */}
        <div className="w-[65%] h-[90%] flex flex-col justify-end z-30 relative">
          
          <div 
            onClick={handleBubbleClick}
            className={`relative w-full h-full bg-[#a3c2b1] rounded-[2.5rem] p-10 flex flex-col shadow-lg border-4 border-[#94b1a1] ${isTyping ? 'cursor-pointer' : ''}`}
          >
             
            {/* The Speech Bubble Tail pointing left */}
            <div className="absolute bottom-[20%] -left-[60px] w-0 h-0 border-y-[18px] border-y-transparent border-r-[60px] border-r-[#94b1a1]" />
            <div className="absolute bottom-[20%] mt-[4px] -left-[54px] w-0 h-0 border-y-[14px] border-y-transparent border-r-[54px] border-r-[#a3c2b1] z-10" />

            {/* Chat History Flow */}
            <div className="flex-1 overflow-y-auto flex flex-col gap-6 pr-4 pl-2 mb-6 min-h-0 no-scrollbar" style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}>
              {messages.map((msg, index) => {
                 const isLatest = index >= messages.length - 1; // Show options only on absolute latest message
                 
                 if (msg.sender === 'user') {
                    return (
                      <div key={msg.id} className="flex flex-col items-end w-full animate-in fade-in slide-in-from-bottom-2 duration-300">
                        <span className="text-[#4e4d69] font-bold mb-1 opacity-70 text-sm tracking-wide">You</span>
                        <span className="text-xl font-bold text-white bg-[#737199] px-6 py-4 rounded-3xl rounded-tr-sm shadow-md max-w-[80%] whitespace-pre-line leading-relaxed">
                          {msg.text}
                        </span>
                      </div>
                    );
                 }
                 
                 if (msg.isSystem) {
                    return (
                      <div key={msg.id} className="flex flex-col items-center w-full">
                         <span className="text-lg font-bold text-white/70 bg-black/20 px-5 py-2 rounded-xl text-center">
                           {msg.text}
                         </span>
                      </div>
                    );
                 }

                 // Meowow's layout
                 return (
                 <div key={msg.id} className={`flex flex-col items-start w-full ${!isLatest ? 'opacity-80' : 'opacity-100'} transition-all duration-300`}>
                   <span className="text-[#4a5d53] font-bold mb-1 opacity-70 text-sm tracking-wide">Meowow</span>
                   
                   <div className="flex flex-col items-start bg-[#e9f2ee] px-8 py-6 rounded-[2rem] rounded-tl-sm shadow-sm w-full max-w-[90%]">
                     <span className="text-2xl font-bold text-[#4a5d53] leading-relaxed mb-4">
                       {msg.typewriter ? (
                         <TypewriterMessage text={msg.text} onComplete={handleTypingComplete} onUpdate={handleTypingUpdate} fastForward={fastForward} />
                       ) : (
                         <>{msg.text}</>
                       )}
                     </span>
                     
                     {/* Mascot Image Response rendering! */}
                     {msg.image && (
                        <div className="w-full flex justify-center py-4 mb-4">
                          <img src={msg.image} className="w-[180px] h-[180px] object-contain drop-shadow-md animate-in zoom-in spin-in-2 duration-500" alt="Generated Drink" />
                        </div>
                     )}

                     {/* Inline Action Options */}
                     {msg.options && msg.options.length > 0 && isLatest && !isTyping && (
                        <div className="flex flex-wrap gap-3 mt-4 w-full justify-center animate-in fade-in slide-in-from-bottom-4 duration-500 delay-150">
                           {msg.options.map((opt, i) => (
                              <button 
                                key={i}
                                onClick={(e) => { e.stopPropagation(); handleSend(opt); }}
                                className={`px-6 py-3 rounded-full text-lg font-bold text-white hover:scale-105 active:scale-95 transition-all shadow-md
                                  ${i === 0 ? 'bg-[#e07a5f] hover:bg-[#d4694f]' : 'bg-[#737199] hover:bg-[#605e83]'}`}
                              >
                                {opt}
                              </button>
                           ))}
                        </div>
                     )}
                   </div>
                 </div>
              )})}
              <div ref={messagesEndRef} />
            </div>

             {/* Input Bar inside the container */}
             <div className="flex items-center gap-3 shrink-0 bg-[#e9f2ee] rounded-full p-2 px-6 shadow-inner mx-2 opacity-80 focus-within:opacity-100 transition-opacity">
                <input 
                  type="text" 
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  onKeyDown={handleKeyDown}
                  disabled={orderStage === 'COMPLETED'}
                  placeholder={orderStage === 'COMPLETED' ? "Order finished!" : "Send Message here..."}
                  className="w-full bg-transparent py-4 text-xl outline-none font-bold text-[#4a5d53] placeholder:text-[#4a5d53]/50 disabled:opacity-50 italic"
                />
                <button 
                  onClick={(e) => { e.stopPropagation(); handleSend(inputText); }}
                  disabled={orderStage === 'COMPLETED' || isTyping || !inputText.trim()}
                  className="p-3 bg-[#737199] text-white hover:bg-[#605e83] disabled:opacity-50 disabled:hover:bg-[#737199] rounded-full transition-colors cursor-pointer shrink-0"
                >
                  <Play className="w-6 h-6 fill-white" />
                </button>
             </div>

          </div>
        </div>

      </div>
    </div>
  );
};

export default Kiosk;
